  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (_req, res) => {
  // In production: authenticate, authorize, and paginate
  const users = [
    { id: 1, name: 'Alice' },   // Omit email unless authenticated
    { id: 2, name: 'Bob' },
  ];
  res.json(users);
});

